// src/components/SectionHeading.js
import React from 'react';
import { Link } from 'react-router-dom';
import { MdArrowForwardIos } from 'react-icons/md';

/**
 * 모든 섹션에서 공통으로 쓰는 제목 헤더.
 * - title: 한글 제목
 * - english: 영문 보조 제목 (선택)
 * - moreLink: "더보기" 링크 경로 (선택)
 * - align: 'left' | 'center'
 */
const SectionHeading = ({
  title,
  english,
  moreLink,
  moreLabel = '더보기',
  align = 'left',
  className = '',
}) => {
  const isCenter = align === 'center';

  return (
    <div className={`mb-8 ${className}`}>
      <div
        className={`flex items-end gap-3 ${
          isCenter ? 'flex-col items-center text-center' : 'justify-between'
        }`}
      >
        <div className={isCenter ? '' : 'flex items-baseline gap-3 flex-wrap'}>
          <h2 className="text-2xl md:text-3xl font-bold tracking-tightish text-ink">
            {title}
          </h2>
          {english && (
            <span className="text-sm md:text-base font-medium text-accent-600">
              {english}
            </span>
          )}
        </div>

        {moreLink && (
          <Link
            to={moreLink}
            className="group inline-flex items-center gap-1.5 text-sm font-medium text-ink-muted hover:text-brand-600 transition-colors whitespace-nowrap"
          >
            {moreLabel}
            <MdArrowForwardIos className="text-xs transition-transform group-hover:translate-x-0.5" />
          </Link>
        )}
      </div>

      {/* 강조 언더라인 */}
      <div
        className={`mt-4 h-[3px] rounded-full bg-gradient-to-r from-brand-600 to-accent-400 ${
          isCenter ? 'mx-auto w-16' : 'w-14'
        }`}
      />
    </div>
  );
};

export default SectionHeading;
